const body = $input.first().json.body || $input.first().json;

const alertId = body.alert_id;
const veredicto = body.veredicto;
const causaRaizCodigo = body.causa_raiz_codigo || null;
const causaRaizTexto = body.causa_raiz_texto || null;
const cerradoPor = body.cerrado_por || body.user_name || 'sistema';
const canalCierre = body.canal_cierre || 'webhook';
const montoRecuperado = Number(body.monto_recuperado || 0);

if (!alertId) throw new Error('alert_id es requerido');
if (!veredicto) throw new Error('veredicto es requerido');
if (!['confirmado','false_positive','escalado','pendiente'].includes(veredicto)) {
  throw new Error(`veredicto inválido: ${veredicto}`);
}

return [{
  json: {
    alert_id: alertId,
    veredicto,
    causa_raiz_codigo: causaRaizCodigo,
    causa_raiz_texto: causaRaizTexto,
    cerrado_por: cerradoPor,
    canal_cierre: canalCierre,
    monto_recuperado: montoRecuperado
  }
}];

const cierreData = $('Validar Datos de Cierre').first().json;
const alertaData = $input.first().json;

if (!alertaData || !alertaData.id) {
  throw new Error(`Alerta ${cierreData.alert_id} no encontrada en opex_alerts`);
}

const generadaEn = new Date(alertaData.generada_en);
const ahora = new Date();
const tiempoHoras = (ahora - generadaEn) / (1000 * 60 * 60);

let iaAcerto = null;
if (cierreData.causa_raiz_codigo && alertaData.causa_raiz_ia) {
  const iaLower = (alertaData.causa_raiz_ia || '').toLowerCase();
  const humanLower = (cierreData.causa_raiz_texto || '').toLowerCase();
  iaAcerto = humanLower.split(' ').some(word => word.length > 4 && iaLower.includes(word));
}

return [{
  json: {
    alert_id: cierreData.alert_id || alertaData.id,
    codigo_alerta: alertaData.codigo_alerta,
    contratista_id: alertaData.contratista_id,
    tipo_servicio: alertaData.tipo_servicio,
    zona: alertaData.zona,
    veredicto: cierreData.veredicto,
    causa_raiz_codigo: cierreData.causa_raiz_codigo,
    causa_raiz_texto: cierreData.causa_raiz_texto,
    causa_raiz_ia: alertaData.causa_raiz_ia,
    ia_acerto: iaAcerto,
    accion_tomada: cierreData.veredicto === 'confirmado' ? 'Alerta confirmada y gestionada' : null,
    monto_recuperado: cierreData.monto_recuperado,
    monto_ajustado: 0,
    cerrado_por: cierreData.cerrado_por,
    canal_cierre: cierreData.canal_cierre,
    tiempo_resolucion_horas: Math.round(tiempoHoras * 10) / 10,
    alert_db_id: alertaData.id,
    nuevo_estado: cierreData.veredicto === 'false_positive' ? 'false_positive' : 'resolved'
  }
}];

const regla = $input.first().json || {};
const threshold = 0.40;
const fpRate = Number(regla.fp_rate || 0);
const fpAlto = fpRate >= threshold;
const fpDisplay = `${(fpRate * 100).toFixed(0)}%`;

const slack_blocks = fpAlto ? [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `⚠️ *Calidad de regla — Revisión sugerida*\nRegla *${regla.codigo_regla}* tiene una tasa de falsos positivos del *${fpDisplay}* en los últimos 30 días (${regla.n_falsos_positivos || 0} FP de ${regla.n_activaciones || 0} activaciones).\n\nEl workflow de recalibración mensual (día 3) propondrá un ajuste de umbral formalmente. Si necesitas ajuste inmediato, modifica \`opex_rules\` en Supabase.`
    }
  }
] : [];

return [{
  json: {
    ...regla,
    fp_rate_alto: fpAlto,
    fp_pct_display: fpDisplay,
    channel: 'C0AVCTBV665',
    slack_blocks
  }
}];
